diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
index c55c40c88bc8..496d46e61433 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCalls.cpp
@@ -2228,8 +2228,55 @@ Instruction *InstCombinerImpl::visitCallInst(CallInst &CI) {
                                      /*MatchBitReversals*/ true))
         return BitOp;
     }
+    // fshl(X, 0, Y) --> shl X, Y if Y < BitWidth
+    // fshl(X, undef, Y) --> shl X, Y if Y < BitWidth
+    if (IID == Intrinsic::fshl &&
+        (match(Op1, m_ZeroInt()) || match(Op1, m_Undef()))) {
+      KnownBits Known = computeKnownBits(II->getArgOperand(2), 0, II);
+      if (Known.getMaxValue().ult(BitWidth))
+        return BinaryOperator::CreateShl(Op0, II->getArgOperand(2));
+      if (isPowerOf2_32(BitWidth)) {
+        Value *ShAmt = Builder.CreateURem(II->getArgOperand(2), ConstantInt::get(Ty, BitWidth));
+        return BinaryOperator::CreateShl(Op0, ShAmt);
+      }
+    }
+
+    // fshl(0, X, Y) --> lshr X, (BW-Y) if Y < BitWidth
+    // fshl(undef, X, Y) --> lshr X, (BW-Y) if Y < BitWidth
+    // But only if Y > 0 because lshr X, BW is poison.
+    if (IID == Intrinsic::fshl &&
+        (match(Op0, m_ZeroInt()) || match(Op0, m_Undef()))) {
+      KnownBits Known = computeKnownBits(II->getArgOperand(2), 0, II);
+      if (Known.getMaxValue().ult(BitWidth) && isKnownNonZero(II->getArgOperand(2), SQ.getWithInstruction(II))) {
+        Value *Sub = Builder.CreateSub(ConstantInt::get(Ty, BitWidth), II->getArgOperand(2));
+        return BinaryOperator::CreateLShr(Op1, Sub);
+      }
+    }

-    // Left or right might be masked.
+    // fshr(X, 0, Y) --> shl X, (BW-Y) if Y < BitWidth
+    // fshr(X, undef, Y) --> shl X, (BW-Y) if Y < BitWidth
+    // But only if Y > 0 because shl X, BW is poison.
+    if (IID == Intrinsic::fshr &&
+        (match(Op1, m_ZeroInt()) || match(Op1, m_Undef()))) {
+      KnownBits Known = computeKnownBits(II->getArgOperand(2), 0, II);
+      if (Known.getMaxValue().ult(BitWidth) && isKnownNonZero(II->getArgOperand(2), SQ.getWithInstruction(II))) {
+        Value *Sub = Builder.CreateSub(ConstantInt::get(Ty, BitWidth), II->getArgOperand(2));
+        return BinaryOperator::CreateShl(Op0, Sub);
+      }
+    }
+
+    // fshr(0, X, Y) --> lshr X, Y if Y < BitWidth
+    // fshr(undef, X, Y) --> lshr X, Y if Y < BitWidth
+    if (IID == Intrinsic::fshr &&
+        (match(Op0, m_ZeroInt()) || match(Op0, m_Undef()))) {
+      KnownBits Known = computeKnownBits(II->getArgOperand(2), 0, II);
+      if (Known.getMaxValue().ult(BitWidth))
+        return BinaryOperator::CreateLShr(Op1, II->getArgOperand(2));
+      if (isPowerOf2_32(BitWidth)) {
+        Value *ShAmt = Builder.CreateURem(II->getArgOperand(2), ConstantInt::get(Ty, BitWidth));
+        return BinaryOperator::CreateLShr(Op1, ShAmt);
+      }
+    }
     if (SimplifyDemandedInstructionBits(*II))
       return &CI;

